s($,"b_O","ow",()=>{var q,p,o,n,m,l,k,j,i="Golasecca",h="Golasecca \u2014 Villa sul Ticino",g="c1_s2",f="riccardo",e="clue_orario_festa",d=null,c="Riccardo",b="c1_s3",a="Sesto Calende",a0="Sesto Calende \u2014 Riva del Ticino",a1="c2_s2",a2="segghy",a3="Segghy",a4="c2_s3",a5="Sesto Calende \u2014 Magazzino di Adriano",a6="c2b_s2",a7="c2b_s3",a8="Somma Lombardo",a9="Somma Lombardo \u2014 Maneggio",b0="c3_s2",b1="c3_s3",b2="Somma Lombardo \u2014 Casa di Cinzia",b3="c3b_s2",b4="c3b_s3",b5="Vergiate",b6="Vergiate \u2014 Officina",b7="c4_s2",b8="c4_s3",b9="Golasecca \u2014 Rifugio per gattini",c0="c5_s2",c1="sandra",c2="c5_s3",c3="Arsago Seprio",c4="Arsago Seprio \u2014 Laboratorio di restauro",c5="c6_s2",c6="c6_s3",c7="Castelletto sopra Ticino",c8="Castelletto sopra Ticino \u2014 Riva del fiume",c9="c7_s2",d0="c7_s3",d1="Golasecca \u2014 Bar di Sandra",d2="Sandra",d3="c8_s2",d4="c8_s3",d5="c9_s2",d6="c9_s3",d7="Golasecca \u2014 Riva del Ticino",d8="c10_accusa",d9="c10_finale_oscuro",e0="clue_confessione",e1=t.B3,e2=A.b([A.d3("Matteo","matteo","Tutti indietro. Nessuno tocchi niente. Segghy... quello non \xe8 il tuo ciondolo?")],e1),e3=t.s,e4=A.b(["clue_vaso_rovesciato"],e3),e5=t.N,e6=t.S,e7=A.aP("La sincerit\xe0 disarma Matteo, ma alcuni ospiti iniziano a sussurrare.","c1_s1_a",B.l,A.T(["matteo",8,"riccardo",2],e5,e6),B.r,g,'D\xec la verit\xe0 subito: "L\'ho perso stasera, non so come sia finito qui."'),e8=A.T(["matteo",-4],e5,e6),e9=t.E4
e8=A.bQ(e2,d,"c1_s1",e4,d,!1,h,d,d,!1,A.b([e7,A.aP("Il silenzio insospettisce Matteo, ma noti un dettaglio che agli altri sfugge.","c1_s1_b",A.b([e],e3),e8,B.r,g,"Resta in silenzio e osserva la scena con attenzione."),A.aP("La prudenza \xe8 legittima, ma agli occhi di alcuni sembri gi\xe0 sulla difensiva.","c1_s1_c",B.l,A.T(["matteo",-6],e5,e6),B.r,g,"Chiedi di poter chiamare un avvocato prima di dire altro.")],e9),"Le luci della festa si riflettono nebbiose sull'acqua scura del Ticino. La musica si interrompe di colpo: un urlo arriva dalla serra in fondo al giardino. Mauro \xe8 a terra, immobile, tra vasi rovesciati e terra sparsa. Accanto al corpo, seminterrato, qualcosa luccica: un ciondolo a forma di cavallo. Il cuore di Segghy si ferma: la sua catenina si \xe8 rotta durante la festa, e quel ciondolo sembra identico al suo.")
e7=A.b([A.d3(c,f,"Segghy, quel ciondolo non basta a incastrarti. Ma dobbiamo muoverci prima che lo facciano loro nella loro testa."),A.d3("Matteo","matteo","Non posso proteggerti ufficialmente, Segghy. Ma se trovi qualcosa, portalo prima a me.")],e1)
e4=A.aP("Riccardo apre sul telefono la mappa investigativa dei paesi limitrofi.","c1_s2_a",B.l,A.T(["riccardo",6],e5,e6),B.r,b,"Accetta l'aiuto di Riccardo e inizia a indagare insieme a lui.")
e2=A.T(["matteo",6],e5,e6)
q=A.ao("y<Oz>")
e2=A.iF("Durante una festa privata tra Golasecca e Sesto Calende, Mauro viene trovato morto. Il ciondolo di Segghy \xe8 sulla scena del crimine.","c1",i,1,"c1_s1",A.b([e8,A.bQ(e7,d,g,B.l,d,!1,h,d,d,!1,A.b([e4,A.aP("Matteo esita, ma ti lascia intuire un dettaglio sull'orario della morte.","c1_s2_b",A.b([e],e3),e2,B.r,b,"Chiedi a Matteo di poter vedere il fascicolo, anche informalmente."),A.aP("Matteo e Riccardo si guardano, sorpresi ma d'accordo.","c1_s2_c",B.l,A.T(["riccardo",3,"matteo",3],e5,e6),B.r,b,"Proponi a entrambi di lavorare insieme, apertamente, tu compresa.")],e9),"I Carabinieri isolano la serra. Matteo ti chiama in disparte per un primo interrogatorio informale, mentre Riccardo cerca di avvicinarsi senza farsi notare dagli altri ospiti. Il ciondolo ritrovato non \xe8 il tuo: \xe8 identico, ma tu il tuo lo indossavi fino a un'ora prima. Qualcuno lo ha raccolto e piazzato l\xec."),A.bQ(B.b_,d,b,A.b(["clue_ciondolo_falso"],e3),d,!0,i,"Non fidarti di chi ti ha dato da mangiare.",d,!1,B.b0,"Torni a casa all'alba, con la nebbia che sale dal Ticino come ogni mattina, ma questa volta sembra diversa: pi\xf9 fitta, pi\xf9 silenziosa. Sai che non sarai pi\xf9 la stessa finch\xe9 non scoprirai chi ha voluto incastrarti. Il tuo telefono vibra.")],q),"Il ciondolo")
e4=A.iF("Con Riccardo, Segghy esplora i sentieri lungo il fiume tra Golasecca e Sesto Calende. Trova impronte, fango e un biglietto bagnato.","c2",a,2,"c2_s1",A.b([A.bQ(A.b([A.d3(c,f,"Non sono impronte di uno che passeggia, Segghy. Qualcuno ha trascinato un peso fino alla riva.")],e1),d,"c2_s1",A.b(["clue_impronte_doppie"],e3),d,!1,a0,d,d,!1,A.b([A.aP("Tra i canneti trovi qualcosa di inaspettato, mezzo sepolto nel fango.","c2_s1_a",A.b(["clue_biglietto_bagnato"],e3),B.r,B.r,a1,"Segui le impronte controcorrente, verso i canneti."),A.aP("Il metodo paga: le foto saranno utili pi\xf9 avanti, ma perdi tempo prezioso.","c2_s1_b",B.l,A.T(["riccardo",4],e5,e6),B.r,a1,"Fotografa tutto con calma prima di muoverti, per non contaminare la scena."),A.aP("Matteo apprezza la procedura corretta, anche se arrivi con pi\xf9 cautela.","c2_s1_c",B.l,A.T(["matteo",5],e5,e6),B.r,a1,"Chiama subito Matteo prima di toccare qualunque cosa.")],e9),"Il sentiero lungo il fiume \xe8 deserto a quest'ora. Riccardo cammina qualche passo avanti, con il telefono puntato verso il terreno umido. \"Qui,\" dice a un certo punto, indicando il fango. Delle impronte doppie, profonde, si allontanano verso l'acqua: qualcuno ha trascinato qualcosa di pesante, di recente."),A.bQ(A.b([A.d3(a3,a2,"Quella barca non \xe8 mai stata cos\xec pulita in vita sua. Qualcuno ha cancellato qualcosa.")],e1),d,a1,B.l,"clue_impronta_estranea",!1,a0,d,B.NO,!1,A.b([A.aP("Trovi tracce di sangue lavate male sul bordo dello scafo.","c2_s2_a",B.l,A.T(["matteo",-2],e5,e6),B.r,a4,"Sali a bordo per controllare da vicino."),A.aP("Matteo arriva in fretta: la collaborazione rafforza la sua fiducia in te.","c2_s2_b",B.l,A.T(["matteo",8],e5,e6),B.r,a4,"Chiama subito Matteo per segnalare la barca."),A.aP("Riccardo lo etichetta per farlo analizzare: potrebbe rivelarsi utile.","c2_s2_c",B.l,A.T(["riccardo",3],e5,e6),A.T(["moreno",4],e5,e6),a4,"Preleva con cura un campione del liquido di pulizia rimasto sullo scafo.")],e9),"Il fiume scorre lento, quasi in ascolto. Riccardo osserva le barche ormeggiate poco pi\xf9 a valle: una di queste ha lo scafo lavato di fresco, in un punto solo. Troppo pulito per essere normale, in un posto dove nessuno pulisce mai niente prima dell'inverno. Sul bordo, alcune tracce si sono impresse nella vernice ancora umida: vale la pena confrontarle con calma."),A.bQ(B.b_,d,a4,B.l,d,!0,a,d,d,!1,B.b0,'Il biglietto bagnato, una volta asciugato con cura da Riccardo, rivela poche parole ancora leggibili: "...al maneggio, dopo mezzanotte...". Il pensiero corre subito a Manuela, e un brivido ti attraversa la schiena. Il fiume, pensi, non dimentica mai niente.')],q),"La riva del Ticino")
e7=A.iF("Adriano, ex socio in affari di Mauro, nasconde un rancore vecchio di anni. Segghy scopre il contratto che gli \xe8 costato l'azienda.","c2b",a,3,"c2b_s1",A.b([A.bQ(A.b([A.d3("Adriano","adriano",'So cosa pensi. "Ex socio rovinato, movente perfetto." Ma io a quella festa non ci sono nemmeno andato.')],e1),d,"c2b_s1",B.l,d,!1,a5,d,d,!1,A.b([A.aP("Adriano si irrigidisce, poi inizia a raccontare, a fatica.","c2b_s1_a",B.l,A.T(["adriano",5],e5,e6),B.r,a6,"Chiedigli direttamente cosa \xe8 successo con Mauro e la societ\xe0."),A.aP("Adriano si rilassa leggermente, meno sulla difensiva.","c2b_s1_b",B.l,A.T(["adriano",8],e5,e6),B.r,a6,"Resta in ascolto, lasciando che sia lui a guidare la conversazione."),A.aP("Adriano si chiude a riccio, sulla difensiva.","c2b_s1_c",B.l,A.T(["adriano",-6],e5,e6),A.T(["adriano",6],e5,e6),a6,"Fagli notare subito che il suo nervosismo non aiuta la sua posizione.")],e9),'Il nuovo "ufficio" di Adriano \xe8 un magazzino spoglio alla periferia di Sesto Calende, ben lontano dai palazzi che un tempo frequentava. Vi trovate tra scatoloni ancora da disfare. Adriano vi accoglie con un sorriso teso, le mani sporche di polvere, gli occhi che si spostano continuamente verso la porta.'),A.bQ(A.b([A.d3("Adriano","adriano","Ho passato anni a immaginare cosa gli avrei detto se l'avessi incontrato di nuovo. Ma quella sera ero a Sesto Calende, da solo, a chiudere l'inventario.")],e1),d,a6,A.b(["clue_contratto_adriano"],e3),d,!1,a5,d,d,!1,A.b([A.aP("Adriano esita: il suo racconto lascia scoperta quasi un'ora.","c2b_s2_a",A.b(["clue_alibi_adriano"],e3),B.r,A.T(["adriano",8],e5,e6),a7,"Chiedigli se qualcuno pu\xf2 confermare che era davvero qui, quella notte."),A.aP("Adriano si commuove, sorpreso dalla tua empatia.","c2b_s2_b",B.l,A.T(["adriano",10],e5,e6),B.r,a7,"Digli che capisci la sua rabbia, senza indagare oltre sull'alibi."),A.aP("Adriano ti guarda come se nessuno gli avesse mai offerto aiuto vero.","c2b_s2_c",B.l,A.T(["adriano",12],e5,e6),B.r,a7,"Proponigli di portare il contratto a un avvocato, per farsi finalmente giustizia.")],e9),'Adriano tira fuori da un cassetto una cartellina consumata: il contratto con cui, anni prima, Mauro si era impossessato delle sue quote societarie, firmato pochi giorni dopo la morte di suo padre, quando non ragionava lucidamente. "Mi ha fregato quando ero pi\xf9 debole," dice, con la voce che trema.'),A.bQ(B.b_,d,a7,B.l,d,!0,a,d,d,!1,B.b0,"Lasci il magazzino con la sensazione di aver visto un uomo consumato pi\xf9 dal rimpianto che dalla furia. Non \xe8 detto che sia innocente, ma il suo dolore sembra vero. Riccardo, in macchina, aggiorna la mappa investigativa con un nuovo nome cerchiato in rosso.")],q),"Il socio scomparso")
e8=A.iF("Il cavallo Nebbia reagisce a un suono preciso. I gattini giocano con un oggetto nascosto nella paglia.","c3",a8,4,"c3_s1",A.b([A.bQ(A.b([A.d3("Manuela","manuela","Segghy, tesoro... non credere a quello che si dice in giro. Io so chi sei davvero.")],e1),d,"c3_s1",B.l,d,!1,a9,d,d,!1,A.b([A.aP("Manuela si irrigidisce appena, poi risponde con voce troppo controllata.","c3_s1_a",B.l,A.T(["manuela",-3],e5,e6),A.T(["manuela",8],e5,e6),b0,"Chiedi a Manuela dove si trovava la notte della festa."),A.aP("Manuela si rilassa e ti racconta di un rumore che ha spaventato la giumenta.","c3_s1_b",B.l,A.T(["manuela",6],e5,e6),B.r,b0,"Rassicurala e chiedi solo di Nebbia, cos\xec nervosa."),A.aP("Il tuo sguardo attento non sfugge a Manuela, che distoglie gli occhi per un istante.","c3_s1_c",B.l,B.r,A.T(["manuela",5],e5,e6),b0,"Osserva in silenzio la sua reazione, senza chiedere nulla.")],e9),"L'odore di fieno e cavalli ti mette quasi a tuo agio, nonostante tutto. Manuela ti accoglie con un abbraccio pi\xf9 lungo del solito. Nebbia, la giumenta grigia, scalpita nel box, nervosa pi\xf9 del normale. I gattini, cresciuti in fretta, rincorrono qualcosa tra la paglia."),A.bQ(A.b([A.d3(a3,a2,"Tranquilla, Nebbia... cosa ti ha spaventato cos\xec tanto?")],e1),d,b0,A.b(["clue_campanello"],e3),d,!1,a9,d,d,!1,A.b([A.aP("Il cavallo si concentra su un punto preciso del fienile, per ora inaccessibile.","c3_s2_a",B.l,A.T(["manuela",3],e5,e6),B.r,b1,"Prova a calmare Nebbia e osserva dove guarda."),A.aP('Manuela distoglie lo sguardo: "Non ne ho idea," dice, troppo in fretta.',"c3_s2_b",B.l,A.T(["manuela",-5],e5,e6),A.T(["manuela",10],e5,e6),b1,"Chiedi subito a Manuela di chi potrebbe essere quel campanello."),A.aP("Un buon istinto investigativo: ora hai una prova che nessuno pu\xf2 negare.","c3_s2_c",B.l,B.r,B.r,b1,"Fotografa il campanello prima di chiedere qualsiasi cosa a chiunque.")],e9),"Tra la paglia, uno dei gattini trascina goffamente un oggetto metallico: un vecchio campanello da bicicletta, ammaccato. Nel momento in cui il campanello tintinna per caso, Nebbia si impenna, tirando con forza verso l'angolo pi\xf9 buio del fienile."),A.bQ(B.b_,d,b1,B.l,d,!0,a8,"Il cavallo ha visto.",d,!1,B.b0,"Lasci il maneggio con pi\xf9 domande che risposte. Il campanello, il nervosismo di Nebbia, lo sguardo sfuggente di Manuela: qualcosa in quel luogo che consideri casa non torna. Il telefono vibra di nuovo.")],q),"Il maneggio di Manuela")
p=A.iF("Cinzia, legata al passato del maneggio, aiuta Segghy a ricostruire con precisione gli orari di quella notte.","c3b",a8,5,"c3b_s1",A.b([A.bQ(A.b([A.d3("Cinzia","cinzia","Quel maneggio doveva essere mio. Mauro me lo ha portato via con un prestito che sapeva benissimo non avrei mai potuto ripagare.")],e1),d,"c3b_s1",A.b(["clue_prestito_cinzia"],e3),d,!1,b2,d,d,!1,A.b([A.aP("Cinzia esita, poi ammette un legame pi\xf9 profondo di quanto sembri.","c3b_s1_a",A.b(["clue_promessa_manuela"],e3),A.T(["cinzia",6],e5,e6),B.r,b3,"Chiedile che rapporto ha oggi con Manuela."),A.aP("Cinzia si offende per il tono, ma risponde comunque.","c3b_s1_b",B.l,B.r,A.T(["cinzia",8],e5,e6),b3,"Chiedile direttamente dove si trovava la notte della festa."),A.aP("Cinzia si scioglie un po', sollevata di non sentirsi accusata.","c3b_s1_c",B.l,A.T(["cinzia",9],e5,e6),B.r,b3,"Ascolta senza giudicare la sua rabbia verso Mauro.")],e9),"Cinzia vive in una casetta a pochi campi dal maneggio che un tempo era suo. Dalla finestra della cucina si vedono ancora i tetti delle scuderie. Vi fa accomodare con un'ospitalit\xe0 rigida, quasi difensiva, come chi ha imparato a proprie spese a non fidarsi troppo in fretta."),A.bQ(A.b([A.d3("Cinzia","cinzia","Se mettiamo in ordine gli orari, forse salta fuori chi mente e chi no.")],e1),d,b3,B.l,"clue_registro_visite",!1,b2,d,B.NQ,!1,A.b([A.aP("Cinzia annuisce, per la prima volta con un mezzo sorriso.","c3b_s2_a",B.l,A.T(["cinzia",6],e5,e6),B.r,b4,"Ringrazia Cinzia per l'aiuto e prometti di tenerla informata."),A.aP('Cinzia si irrigidisce: "Ci ho pensato. Non l\'ho fatto."',"c3b_s2_b",B.l,B.r,A.T(["cinzia",10],e5,e6),b4,"Chiedile se ha mai pensato di vendicarsi di persona."),A.aP("Cinzia accetta, sollevata di non dover portare da sola quel peso.","c3b_s2_c",B.l,A.T(["matteo",4,"cinzia",4],e5,e6),B.r,b4,"Proponile di condividere il quaderno con Matteo, ufficialmente.")],e9),"Cinzia tira fuori un vecchio quaderno in cui, per anni, ha annotato ogni movimento sospetto legato al maneggio: un'abitudine quasi ossessiva, dice, \"per non impazzire\". Insieme provate a incrociare i suoi appunti con quello che sapete gi\xe0, per ricostruire l'esatta sequenza di quella notte."),A.bQ(B.b_,d,b4,B.l,d,!0,a8,d,d,!1,B.b0,"Il registro di Cinzia, incrociato con quanto gi\xe0 sapete, restituisce un'incongruenza precisa: qualcuno ha lasciato il maneggio molto pi\xf9 tardi di quanto dichiarato. Riccardo fischia piano, guardando la mappa investigativa aggiornarsi da sola sul suo schermo.")],q),"Il debito di Cinzia")
o=A.iF("A Vergiate, Kledian consegna un telefono rotto. Il giocatore deve sbloccarlo per recuperare messaggi cancellati.","c4",b5,6,"c4_s1",A.b([A.bQ(A.b([A.d3("Kledian","kledian","Ero l'ultimo ad averlo visto vivo, lo so cosa pensi. Ma io ho solo riparato la sua auto, quella sera.")],e1),d,"c4_s1",B.l,d,!1,b6,d,d,!1,A.b([A.aP("Kledian si apre e ti offre un dettaglio in pi\xf9 sull'orario.","c4_s1_a",B.l,A.T(["kledian",8],e5,e6),B.r,b7,"Chiedi a Kledian di raccontarti esattamente cosa \xe8 successo quella sera."),A.aP("Kledian te lo consegna, un po' sulla difensiva.","c4_s1_b",B.l,A.T(["kledian",-2],e5,e6),B.r,b7,"Vai dritta al punto e chiedi il telefono."),A.aP("Kledian sembra sinceramente sorpreso dal gesto.","c4_s1_c",B.l,A.T(["kledian",10],e5,e6),B.r,b7,"Offriti di pagare tu la riparazione dell'auto, come segno di fiducia.")],e9),'L\'officina di Kledian sa di olio motore e metallo caldo. Lui ti aspetta con le mani ancora sporche di grasso, nervoso, come chi ha tenuto un segreto troppo a lungo. Sul banco, un telefono con lo schermo incrinato: quello di Mauro, portato "per un finto controllo" e mai restituito.'),A.bQ(A.b([A.d3(c,f,"Se troviamo la combinazione giusta, dentro c'\xe8 tutto quello che Mauro voleva tenere nascosto.")],e1),d,b7,B.l,"clue_telefono_mauro",!1,b6,d,B.NN,!1,A.b([A.aP("Trovi tracce di ricatti multipli, con nomi che conosci fin troppo bene.","c4_s2_a",A.b(["clue_messaggi_cancellati"],e3),B.r,B.r,b8,"Leggi con cura tutti i messaggi recuperati, uno per uno."),A.aP("Matteo apprezza la trasparenza, ma perdi tempo prima di poter leggere tutto tu stessa.","c4_s2_b",B.l,A.T(["matteo",6],e5,e6),B.r,b8,"Passa subito i dati a Matteo, per fare le cose in modo corretto."),A.aP("Una scelta discreta: trovi quello che cercavi, senza scavare oltre.","c4_s2_c",B.l,A.T(["manuela",4],e5,e6),B.r,b8,"Cerca solo i messaggi con Manuela, per rispetto della privacy degli altri.")],e9),'Riccardo collega il telefono a un piccolo dispositivo che ha costruito lui stesso. "Serve un codice a quattro cifre," dice. "Proviamo con qualcosa che Mauro avrebbe usato: una data, un nome, un luogo importante per lui." Kledian, rovistando tra i documenti dell\'ultima manutenzione dell\'auto, potrebbe avere proprio il dettaglio che serve.'),A.bQ(B.b_,d,b8,B.l,d,!0,b5,d,d,!1,B.b0,"Nella lista dei contatti ricattati compaiono nomi che ti gelano il sangue: persone che conosci, che frequenti, di cui ti fidi. La lista di sospettati si allarga, ma allo stesso tempo la verit\xe0 sembra pi\xf9 vicina.")],q),"Il telefono di Kledian")
n=A.iF("Gaia e Anna rivelano che uno dei gattini \xe8 stato trovato vicino alla villa la notte dell'omicidio.","c5",i,7,"c5_s1",A.b([A.bQ(A.b([A.d3("Gaia","gaia","Non l'avevamo mai visto prima. \xc8 comparso dal nulla, quella notte, infreddolito.")],e1),d,"c5_s1",A.b(["clue_gattino_infreddolito"],e3),d,!1,b9,d,d,!1,A.b([A.aP("Sotto le dita senti qualcosa di rigido cucito nella fodera del collare.","c5_s1_a",B.l,B.r,B.r,c0,"Esamina con calma il collare del gattino."),A.aP("Anna, pi\xf9 precisa della sorella, disegna una mappa a mano sul retro di uno scontrino.","c5_s1_b",B.l,A.T(["anna",8],e5,e6),B.r,c0,"Chiedi ad Anna di descrivere esattamente dove l'ha trovato."),A.aP('Gaia ci pensa su: "Forse s\xec, qualche volta, per gli avanzi."',"c5_s1_c",B.l,A.T(["gaia",4],e5,e6),A.T(["sandra",4],e5,e6),c0,"Chiedi a Gaia se il gattino si aggirava gi\xe0 prima vicino al bar di Sandra.")],e9),'Il piccolo rifugio di Gaia e Anna, a due passi dal Ticino, \xe8 pieno di scatole di cartone trasformate in cucce e di miagolii. Anna ti osserva in silenzio per un attimo, poi ti porge un gattino tremante. "Questo l\'abbiamo trovato la notte della festa," dice, "vicino alla villa. Aveva le zampe sporche di fango."'),A.bQ(A.b([A.d3("Anna","anna","Non \xe8 fango della villa. \xc8 lo stesso fango della riva vicino al maneggio di Manuela.")],e1),d,c0,A.b(["clue_microscheda","clue_fango_zampe"],e3),d,!1,b9,d,d,!1,A.b([A.aP("Le due sorelle ti stringono la mano, fiduciose.","c5_s2_a",B.l,A.T(["gaia",6,"anna",6],e5,e6),B.r,c2,"Ringrazia Gaia e Anna e prometti di tenerle aggiornate."),A.aP("Gaia esita, protettiva verso i suoi gattini, ma alla fine acconsente.","c5_s2_b",B.l,A.T(["gaia",-3],e5,e6),B.r,c2,"Chiedi se puoi portare via subito la microscheda per farla analizzare."),A.aP("Un piccolo gesto di rispetto che Gaia e Anna non dimenticheranno.","c5_s2_c",B.l,A.T(["riccardo",4,"gaia",3],e5,e6),B.r,c2,"Analizza tu stessa il fango con Riccardo, senza disturbare oltre le sorelle.")],e9),"Con delicatezza, apri la fodera interna del collare: dentro, avvolta in un fazzoletto, c'\xe8 una microscheda sporca di fango. Anna la osserva a lungo, poi confronta il fango sulle zampe del gattino con una foto scattata da Riccardo alla riva vicino al maneggio: combaciano."),A.bQ(B.b_,d,c2,B.l,d,!0,i,"I gattini hanno portato via la prova sbagliata.",d,!1,B.b0,"Sofia, contattata da Riccardo, si offre di analizzare il contenuto della scheda: dice di riconoscere qualcosa legato ai suoi studi di archeologia. Un nuovo messaggio anonimo arriva mentre esci dal rifugio.")],q),"Le sorelle del rifugio")
m=A.bQ(A.b([A.d3("Sofia","sofia","Questa non \xe8 una tomba qualunque, Segghy. \xc8 collegata alla cultura di Golasecca. Se \xe8 autentica, vale una fortuna \u2014 e non solo in senso economico.")],e1),d,"c6_s1",A.b(["clue_foto_tomba"],e3),d,!1,c4,d,d,!1,A.b([A.aP("Sofia esita, poi fa il nome di Alessandra, la restauratrice.","c6_s1_a",B.l,A.T(["sofia",7],e5,e6),B.r,c5,"Chiedi a Sofia chi altro conosce l'esistenza di questa tomba."),A.aP("Sofia accetta di accompagnarti, un po' nervosa.","c6_s1_b",B.l,A.T(["sofia",3],e5,e6),B.r,c5,"Proponi di andare subito a parlare con Alessandra."),A.aP("Sofia annuisce, sollevata che qualcuno pensi prima al sito che allo scoop.","c6_s1_c",B.l,A.T(["sofia",6],e5,e6),B.r,c5,"Chiedi a Sofia di tenere per ora il ritrovamento segreto, per proteggerlo.")],e9),"Sofia ti aspetta davanti a un vecchio laboratorio di restauro, gli occhi accesi dall'entusiasmo nonostante la gravit\xe0 della situazione. Le fotografie della microscheda, ingrandite su uno schermo, mostrano una tomba nascosta nel bosco, di un'epoca ben pi\xf9 antica di quanto chiunque sospettasse.")
l=A.b([A.d3("Alessandra","alessandra","Mauro sapeva che avevo falsificato una datazione, anni fa. Mi ha ricattata. Confronta pure le due mappe, se vuoi la prova.")],e1)
k=A.T(["alessandra",10],e5,e6)
j=A.T(["alessandra",-6],e5,e6)
return A.b([e2,e4,e7,e8,p,o,n,A.iF("Sofia scopre che le mappe archeologiche sono state alterate da Alessandra.","c6",c3,8,"c6_s1",A.b([m,A.bQ(l,d,c5,B.l,"clue_mappa_alterata",!1,c4,d,B.NP,!1,A.b([A.aP("Alessandra si rilassa visibilmente e ti racconta un ultimo dettaglio.","c6_s2_a",A.b(["clue_leggenda_fibula"],e3),k,j,c6,"Credile e offrile il tuo aiuto per uscire dal ricatto."),A.aP("Alessandra si chiude, sulla difensiva.","c6_s2_b",B.l,A.T(["alessandra",-6],e5,e6),A.T(["alessandra",10],e5,e6),c6,"Fai notare che nascondere prove non l'aiuta di certo."),A.aP("Alessandra esita a lungo, poi accetta, sollevata.","c6_s2_c",B.l,A.T(["alessandra",8,"matteo",3],e5,e6),A.T(["alessandra",-4],e5,e6),c6,"Proponile di denunciare formalmente il ricatto alle autorit\xe0.")],e9),"Alessandra vi riceve tra pennelli e resine, le mani che tremano appena. Sul tavolo, due copie della stessa mappa archeologica: quella originale di Sofia e quella trovata tra gli effetti di Mauro. A un primo sguardo sembrano identiche, ma qualcosa, punto per punto, non torna."),A.bQ(B.b_,d,c6,B.l,d,!0,c3,d,d,!1,B.b0,"Mentre tornate verso l'auto, Sofia ti confida di sentirsi osservata da giorni. Le dici di stare attenta: se Mauro cercava quella tomba, qualcun altro potrebbe cercarla ancora, ed essere disposto a tutto per trovarla.")],q),"La mappa falsa"),A.iF("Moreno confessa di aver spento una telecamera, ma sostiene di averlo fatto per paura.","c7",c7,9,"c7_s1",A.b([A.bQ(A.b([A.d3("Moreno","moreno","Se sei qui per la telecamera... s\xec, l'ho spenta io. Ma giuro che non ho fatto niente a Mauro.")],e1),d,"c7_s1",B.l,d,!1,c8,d,d,!1,A.b([A.aP("Moreno si rilassa e ti mostra la posizione esatta della telecamera.","c7_s1_a",B.l,A.T(["moreno",9],e5,e6),B.r,c9,"Ascoltalo senza giudicare, lascialo raccontare."),A.aP("Moreno si irrigidisce, ma risponde comunque, a denti stretti.","c7_s1_b",B.l,A.T(["moreno",-3],e5,e6),A.T(["moreno",8],e5,e6),c9,"Chiedigli direttamente perch\xe9 Mauro lo minacciava."),A.aP("Il gesto disarma Moreno pi\xf9 di qualsiasi domanda.","c7_s1_c",B.l,A.T(["moreno",12],e5,e6),B.r,c9,"Portagli qualcosa da bere e siediti accanto a lui, in silenzio.")],e9),"Sulla riva opposta del Ticino, Moreno pattuglia ogni notte un tratto di argine per conto del comune. Lo trovi seduto su una panchina di legno consumata, lo sguardo perso sull'acqua. Sembra invecchiato di dieci anni in una settimana."),A.bQ(A.b([A.d3("Moreno","moreno","L'ho vista solo stamattina, questa. Non so chi sia, ma quella sagoma non mi convince.")],e1),d,c9,A.b(["clue_video_incappucciato","clue_telecamera_spenta"],e3),d,!1,c8,d,d,!1,A.b([A.aP("Notate un dettaglio: una bicicletta appoggiata poco distante, con qualcosa che tintinna.","c7_s2_a",B.l,A.T(["riccardo",5],e5,e6),B.r,d0,"Studia il video fotogramma per fotogramma con Riccardo."),A.aP("Matteo promette di aprire un fascicolo ufficiale sulla figura incappucciata.","c7_s2_b",B.l,A.T(["matteo",7],e5,e6),B.r,d0,"Porta subito il video a Matteo."),A.aP('Moreno ci pensa: "Una volta, forse. In bicicletta, tardi."',"c7_s2_c",B.l,B.r,A.T(["sandra",6,"moreno",-3],e5,e6),d0,"Chiedi a Moreno se ha mai visto Sandra aggirarsi da queste parti, di notte.")],e9),"Moreno ti mostra su un vecchio computer portatile i filmati di un'altra telecamera, quella che aveva dimenticato di spegnere. Nel video, di notte, una figura incappucciata si avvicina alla riva e getta qualcosa nell'acqua scura, prima di sparire tra gli alberi."),A.bQ(B.b_,d,d0,B.l,d,!0,c7,d,d,!1,B.b0,'Tornando verso casa, ripensi al tintinnio nel video. Un campanello da bicicletta, forse lo stesso che ha spaventato Nebbia. I pezzi iniziano, lentamente, a incastrarsi. "Il Ticino restituisce tutto," pensi, ricordando l\'ultimo messaggio anonimo.')],q),"Il guardiano del fiume"),A.iF("Sandra tradisce una frase che solo l'assassino poteva conoscere.","c8",i,10,"c8_s1",A.b([A.bQ(A.b([A.d3(d2,c1,"Povera Segghy, con tutto quello che ti sta succedendo. Se ti serve qualcuno con cui parlare, io ci sono sempre.")],e1),d,"c8_s1",B.l,d,!1,d1,d,d,!1,A.b([A.aP("Sandra ascolta con attenzione, forse troppa attenzione.","c8_s1_a",B.l,A.T(["sandra",5],e5,e6),B.r,d3,"Racconta a Sandra i dettagli che hai scoperto finora, per vedere come reagisce."),A.aP("Sandra, senza pressioni, si lascia andare a qualche parola di troppo.","c8_s1_b",B.l,B.r,B.r,d3,"Resta vaga e lasciala parlare, osservando le sue reazioni."),A.aP("Un approccio prudente: osservi il bar, i clienti, le abitudini di Sandra.","c8_s1_c",B.l,B.r,B.r,d3,"Ordina qualcosa e lascia scorrere la conversazione su altro, per ora.")],e9),"Il bar di Sandra \xe8 il cuore pettegolo di Golasecca: tutti passano di l\xec, prima o poi. Sandra ti accoglie con il solito sorriso caldo e un caff\xe8 che non hai nemmeno ordinato. \xc8 lei che, negli anni, ha ascoltato pi\xf9 segreti di chiunque altro in paese."),A.bQ(A.b([A.d3(a3,a2,"Sandra... come fai a sapere esattamente dove si trovava il corpo?"),A.d3(d2,c1,"Oh, non... l'avr\xf2 sentito dire in giro, sai come sono i paesi piccoli.")],e1),d,d3,A.b(["clue_frase_sandra"],e3),d,!1,d1,d,d,!1,A.b([A.aP("Sandra si ricompone, ma tu non dimenticherai quella frase.","c8_s2_a",B.l,B.r,A.T(["sandra",8],e5,e6),d4,"Non insistere oltre, ma prendi nota del dettaglio per Riccardo e Matteo."),A.aP("Sandra si irrigidisce visibilmente e cambia argomento in fretta.","c8_s2_b",B.l,A.T(["sandra",-8],e5,e6),A.T(["sandra",4],e5,e6),d4,"Incalza Sandra, chiedendole di essere pi\xf9 precisa."),A.aP("Sandra si rilassa, convinta di essere passata inosservata.","c8_s2_c",B.l,A.T(["sandra",3],e5,e6),A.T(["sandra",12],e5,e6),d4,"Fingi di non aver notato nulla, ma prendi mentalmente nota di tutto.")],e9),'Parlando della serata della festa, Sandra dice, quasi distratta, che Mauro \xe8 stato trovato "vicino alla cassapanca, con la testa girata verso la vetrata". Un dettaglio mai comparso su nessun giornale, mai raccontato pubblicamente da nessuno. Solo chi era l\xec quella notte poteva saperlo.'),A.bQ(B.b_,d,d4,B.l,d,!0,i,d,d,!1,B.b0,"Esci dal bar con la testa piena di dubbi. Sandra, la persona che ascolta tutti senza mai raccontare nulla di s\xe9: possibile che il suo silenzio nascondesse molto pi\xf9 di un semplice pettegolezzo?")],q),"La verit\xe0 al bar"),A.iF("Il cavallo Nebbia guida Segghy verso una zona nascosta del maneggio.","c9",a8,11,"c9_s1",A.b([A.bQ(A.b([A.d3(a3,a2,"Lo so, Nebbia. Andiamo a vedere insieme, allora.")],e1),d,"c9_s1",B.l,d,!1,a9,d,d,!1,A.b([A.aP("Il cavallo cammina sicuro fino a una tavola di legno smossa di recente.","c9_s1_a",B.l,B.r,B.r,d5,"Porta Nebbia fuori dal box e lasciala guidarti."),A.aP("Impieghi pi\xf9 tempo, ma eviti di agitare ulteriormente il cavallo.","c9_s1_b",B.l,B.r,B.r,d5,"Ispeziona da sola l'angolo del fienile, senza coinvolgere Nebbia."),A.aP("Un gesto quasi superstizioso, ma ti fa sentire meno una traditrice.","c9_s1_c",B.l,A.T(["manuela",5],e5,e6),B.r,d5,"Chiedi mentalmente permesso a Manuela, anche se non pu\xf2 sentirti.")],e9),"Torni al maneggio con il campanello da bicicletta ritrovato tra gli effetti recuperati. Manuela non c'\xe8: \xe8 il momento giusto per capire cosa nasconda davvero quel fienile. Fai suonare il campanello vicino al box di Nebbia: la giumenta si agita di nuovo, tirando verso lo stesso angolo buio di sempre."),A.bQ(A.b([A.d3(c,f,"Segghy... questi documenti provano che Manuela doveva soldi a Mauro da anni. Un movente enorme.")],e1),d,d5,A.b(["clue_bottone_strappato","clue_documenti_maneggio","clue_macchia_scura"],e3),d,!1,a9,d,d,!1,A.b([A.aP("Manuela, in lacrime, ammette di aver incontrato Mauro quella notte \u2014 ma giura di non averlo ucciso.","c9_s2_a",B.l,A.T(["manuela",-5],e5,e6),A.T(["manuela",10],e5,e6),d6,"Vai a cercare Manuela e chiedile una spiegazione, faccia a faccia."),A.aP("Matteo promette discrezione, ma ora l'indagine ufficiale si stringe intorno al maneggio.","c9_s2_b",B.l,A.T(["matteo",8,"manuela",-8],e5,e6),A.T(["manuela",14],e5,e6),d6,"Porta tutto a Matteo prima di parlare con Manuela."),A.aP("Riccardo non \xe8 del tutto d'accordo, ma rispetta la tua scelta.","c9_s2_c",B.l,A.T(["riccardo",-3],e5,e6),A.T(["manuela",6],e5,e6),d6,"Custodisci tu stessa i documenti finch\xe9 non avrai capito tutto.")],e9),"Sotto la tavola smossa trovi i segni di una colluttazione: un bottone strappato, incastrato tra le assi, e una macchia scura sul pavimento che qualcuno ha provato a coprire con la paglia fresca. In una piccola cassa di metallo, nascosti, i documenti che Manuela cercava disperatamente di recuperare da Mauro."),A.bQ(B.b_,d,d6,B.l,d,!0,a8,"Il Ticino restituisce tutto.",d,!1,B.b0,"Manuela ti confessa, con la voce spezzata, di aver attirato Mauro al maneggio quella notte per riprendersi i documenti sul debito, e che altri \u2014 Adriano, Moreno, Alessandra \u2014 avevano ciascuno un motivo per essere l\xec. Ma nessuno, giura, gli ha dato il colpo finale. Manca ancora un nome. Il tuo telefono vibra un'ultima volta.")],q),"Nebbia ricorda"),A.iF("Confronto finale sulle rive del fiume. Le scelte del giocatore determinano il finale.","c10",i,12,"c10_s1",A.b([A.bQ(A.b([A.d3(c,f,"Sei sicura di voler fare questo da sola? Posso avvertire Matteo, farlo venire con noi.")],e1),d,"c10_s1",B.l,d,!1,d7,d,d,!1,A.b([A.aP("Matteo si nasconde a distanza, pronto a intervenire.","c10_s1_a",B.l,A.T(["matteo",5],e5,e6),B.r,d8,"Chiedi a Riccardo di avvertire Matteo e farlo arrivare sulla riva."),A.aP("Riccardo non \xe8 convinto, ma rispetta la tua scelta.","c10_s1_b",B.l,A.T(["riccardo",-3],e5,e6),B.r,d8,"Vai da sola: vuoi guardare Sandra negli occhi senza testimoni."),A.aP("Riccardo, teso ma presente, ti segue sulla riva a distanza di sicurezza.","c10_s1_c",B.l,A.T(["riccardo",6],e5,e6),B.r,d8,"Porta con te Riccardo, ma non Matteo: vuoi testimoni di cui ti fidi.")],e9),"Riccardo ha ricostruito l'intera catena di eventi collegando ogni indizio: il campanello, il fango, la microscheda, la frase di troppo al bar. Un solo tassello manca ancora, ma tutto porta nello stesso punto: la riva del Ticino, dove tutto \xe8 iniziato molto prima della morte di Mauro. Convochi Sandra l\xec, con la scusa di una passeggiata."),A.bQ(B.b_,d,d8,B.l,d,!1,d7,d,d,!0,B.b0,"Sei arrivata sulla riva del Ticino. Riccardo apre sul telefono la mappa dell'indagine costruita insieme, capitolo dopo capitolo: indizi, contraddizioni, sguardi sfuggenti, alibi incrinati. Prima di fare qualunque altra mossa, \xe8 arrivato il momento di dire ad alta voce un nome. Ripensa a tutto quello che hai scoperto: chi accusi?"),A.bQ(A.b([A.d3(d2,c1,"Bella giornata per una passeggiata, vero? Anche se so che non sei qui solo per quello.")],e1),d,"c10_s2",B.l,d,!1,d7,d,d,!1,A.b([A.aP("Sandra impallidisce, poi inizia lentamente a raccontare.","c10_s2_a",B.l,B.r,B.r,"c10_confronto_esito","Affronta Sandra con tutte le prove raccolte e chiedile la verit\xe0."),A.aP("Sandra ti guarda a lungo, poi annuisce piano, in lacrime.","c10_s2_b",B.l,B.r,B.r,d9,"Lasciale intendere che sai tutto, ma dalle la possibilit\xe0 di sparire in silenzio.")],e9),"Sandra ti aspetta gi\xe0 sulla riva, le mani strette intorno a una tazza di caff\xe8 da asporto, come sempre. La nebbia sale lenta dall'acqua. \xc8 il momento di scegliere come affrontarla: con tutte le prove che hai raccolto, o lasciando che il fiume custodisca ancora il suo silenzio."),A.bQ(B.b_,"oscuro",d9,A.b([e0],e3),d,!0,d7,d,d,!1,B.b0,"Sandra ti racconta tutto, in un filo di voce rotto dal pianto: suo fratello, il Ticino, l'incidente archiviato in fretta, la rabbia sopita per anni dietro il bancone del bar. Mauro l'ha provocata con la sua confessione fredda, quella notte al maneggio, e lei ha perso il controllo. Ti guarda negli occhi: \"Ora tocca a te decidere.\" Scegli di lasciare che il fiume custodisca ancora questo segreto. Il caso si chiude come irrisolto. Porterai questo peso con te, chiedendoti per sempre se sia stata la scelta giusta."),A.bQ(B.b_,"buono","c10_finale_buono",A.b([e0],e3),d,!0,d7,d,d,!1,B.b0,"Le prove che hai raccolto bastano a ricostruire la verit\xe0 e a scagionarti definitivamente agli occhi di Matteo e dei Carabinieri. Sandra viene affidata alla giustizia, Manuela evita le conseguenze peggiori del ricatto, e il reperto archeologico viene consegnato alle autorit\xe0 competenti. Decidi di restare a Golasecca: il maneggio di Manuela diventer\xe0, con il tuo aiuto, un vero rifugio per cavalli e gattini abbandonati. Nebbia, finalmente tranquilla, sar\xe0 la prima guardiana del nuovo progetto."),A.bQ(B.b_,"perfetto","c10_finale_perfetto",A.b([e0],e3),d,!0,d7,d,d,!1,B.b0,"Ogni indizio, ogni conversazione, ogni scelta ti ha portata esattamente qui. Con le prove al completo e Matteo pronto a intervenire da dietro i canneti, Sandra crolla e confessa ogni dettaglio, davanti a un testimone ufficiale, proprio nel punto della riva dove anni prima \xe8 morto suo fratello. Giustizia e verit\xe0, per una volta, coincidono. Salvi anche Sofia da chi cercava ancora la tomba nel bosco, recuperi il reperto, e torni a casa sapendo di aver visto fino in fondo il silenzio del Ticino."),A.bQ(B.b_,"erroneo","c10_finale_erroneo",B.l,d,!0,d7,d,d,!1,B.b0,"Il nome esce dalla tua bocca prima ancora di averlo deciso fino in fondo: {accusato}. Il silenzio che segue \xe8 peggiore di qualunque urlo. {accusato} nega tutto, sotto shock, e le prove che hai raccolto non bastano a reggere un'accusa cos\xec diretta, pronunciata davanti a tutti. Riccardo ti guarda, in cerca delle parole giuste. Non ce ne sono.")],q),"Il silenzio del Ticino")],A.ao("y<jv>"))})
